SELECT team_name
FROM teams
WHERE LENGTH(team_name) = (
    SELECT MAX(LENGTH(team_name))
    FROM teams
);

SELECT team_name
FROM teams
WHERE league = (SELECT league FROM teams WHERE team_name = 'Team X');

SELECT match_id, date, home_team, away_team
FROM matches
WHERE home_team = 'Team X' OR away_team = 'Team X';

SELECT match_id, date, home_team, home_goals
FROM matches
WHERE home_team = 'FC Barcelona' AND away_team = 'Real Madrid';
